22	/********************************************************************
23	 * Convert string to the enumerate of configuration protocol type
24	 *******************************************************************/
25	static e_config_protocol_type string_to_config_protocol_type(
26	  const std::string& type_string) {
27	  for (size_t itype = 0; itype < NUM_CONFIG_PROTOCOL_TYPES; ++itype) {
28	    if (std::string(CONFIG_PROTOCOL_TYPE_STRING[itype]) == type_string) {
29	      return static_cast<e_config_protocol_type>(itype);
30	    }
31	  }
32	
33	  return NUM_CONFIG_PROTOCOL_TYPES;
34	}
