36	/********************************************************************
37	 * Convert string to the enumerate of BL/WL protocol type
38	 *******************************************************************/
39	static e_blwl_protocol_type string_to_blwl_protocol_type(
40	  const std::string& type_string) {
41	  for (size_t itype = 0; itype < NUM_BLWL_PROTOCOL_TYPES; ++itype) {
42	    if (std::string(BLWL_PROTOCOL_TYPE_STRING[itype]) == type_string) {
43	      return static_cast<e_blwl_protocol_type>(itype);
44	    }
45	  }
46	
47	  return NUM_BLWL_PROTOCOL_TYPES;
48	}
