50	/********************************************************************
51	 * Parse XML codes of a <programming_clock> to an object of configuration
52	 *protocol
53	 *******************************************************************/
54	static void read_xml_ccff_prog_clock(pugi::xml_node& xml_progclk,
55	                                     const pugiutil::loc_data& loc_data,
56	                                     ConfigProtocol& config_protocol) {
57	  /* Find the type of configuration protocol */
58	  std::string port_attr =
59	    get_attribute(xml_progclk, XML_CONFIG_PROTOCOL_CCFF_PROG_CLOCK_PORT_ATTR,
60	                  loc_data)
61	      .as_string();
62	
63	  std::string indices_attr =
64	    get_attribute(xml_progclk, XML_CONFIG_PROTOCOL_CCFF_PROG_CLOCK_INDICES_ATTR,
65	                  loc_data)
66	      .as_string();
67	
68	  openfpga::BasicPort port = openfpga::PortParser(port_attr).port();
69	
70	  config_protocol.set_prog_clock_pin_ccff_head_indices_pair(port, indices_attr);
71	}
72	
73	/********************************************************************
74	 * Parse XML codes of a <bl> to an object of configuration protocol
75	 *******************************************************************/
76	static void read_xml_bl_protocol(pugi::xml_node& xml_bl_protocol,
77	                                 const pugiutil::loc_data& loc_data,
78	                                 ConfigProtocol& config_protocol) {
79	  /* Find the type of configuration protocol */
80	  const char* type_attr =
81	    get_attribute(xml_bl_protocol, "protocol", loc_data).value();
82	  /* Translate the type of design technology to enumerate */
83	  e_blwl_protocol_type blwl_protocol_type =
84	    string_to_blwl_protocol_type(std::string(type_attr));
85	
86	  if (NUM_BLWL_PROTOCOL_TYPES == blwl_protocol_type) {
87	    archfpga_throw(loc_data.filename_c_str(), loc_data.line(xml_bl_protocol),
88	                   "Invalid 'protocol' attribute '%s'\n", type_attr);
89	  }
90	
91	  config_protocol.set_bl_protocol_type(blwl_protocol_type);
92	
93	  /* only applicable to shift-registor protocol
94	   * - Find the memory model to build shift register chains
95	   * - Find the number of shift register chains for each protocol
96	   */
97	  if (BLWL_PROTOCOL_SHIFT_REGISTER == blwl_protocol_type) {
98	    config_protocol.set_bl_memory_model_name(
99	      get_attribute(xml_bl_protocol, "circuit_model_name", loc_data)
100	        .as_string());
101	    config_protocol.set_bl_num_banks(get_attribute(xml_bl_protocol, "num_banks",
102	                                                   loc_data,
103	                                                   pugiutil::ReqOpt::OPTIONAL)
104	                                       .as_int(1));
105	  }
106	}
