108	/********************************************************************
109	 * Parse XML codes of a <wl> to an object of configuration protocol
110	 *******************************************************************/
111	static void read_xml_wl_protocol(pugi::xml_node& xml_wl_protocol,
112	                                 const pugiutil::loc_data& loc_data,
113	                                 ConfigProtocol& config_protocol) {
114	  /* Find the type of configuration protocol */
115	  const char* type_attr =
116	    get_attribute(xml_wl_protocol, "protocol", loc_data).value();
117	  /* Translate the type of design technology to enumerate */
118	  e_blwl_protocol_type blwl_protocol_type =
