152	/********************************************************************
153	 * Parse XML codes of design technology of a circuit model to circuit library
154	 *******************************************************************/
155	static void read_xml_model_design_technology(pugi::xml_node& xml_model,
156	                                             const pugiutil::loc_data& loc_data,
157	                                             CircuitLibrary& circuit_lib,
158	                                             const CircuitModelId& model) {
159	  auto xml_design_tech =
160	    get_single_child(xml_model, "design_technology", loc_data);
161	
162	  /* Identify if the circuit model power-gated */
163	  circuit_lib.set_model_is_power_gated(
164	    model, get_attribute(xml_design_tech, "power_gated", loc_data,
165	                         pugiutil::ReqOpt::OPTIONAL)
166	             .as_bool(false));
167	
168	  /* Identify the type of design technology */
169	  const char* type_attr =
170	    get_attribute(xml_design_tech, "type", loc_data).value();
171	  /* Translate the type of design technology to enumerate */
172	  e_circuit_model_design_tech design_tech_type =
173	    string_to_design_tech_type(std::string(type_attr));
174	
175	  if (NUM_CIRCUIT_MODEL_DESIGN_TECH_TYPES == design_tech_type) {
176	    archfpga_throw(loc_data.filename_c_str(), loc_data.line(xml_design_tech),
177	                   "Invalid 'type' attribute '%s'\n", type_attr);
178	  }
179	
180	  circuit_lib.set_model_design_tech_type(model, design_tech_type);
181	
182	  /* Parse exclusive attributes for inverters and buffers */
183	  if (CIRCUIT_MODEL_INVBUF == circuit_lib.model_type(model)) {
184	    /* Identify the topology of the buffer */
185	    const char* topology_attr =
186	      get_attribute(xml_design_tech, "topology", loc_data).value();
187	    /* Translate the type of buffer to enumerate */
188	    e_circuit_model_buffer_type buf_type =
189	      string_to_buffer_type(std::string(topology_attr));
190	
191	    if (NUM_CIRCUIT_MODEL_BUF_TYPES == buf_type) {
192	      archfpga_throw(loc_data.filename_c_str(), loc_data.line(xml_design_tech),
193	                     "Invalid 'topology' attribute '%s'\n", topology_attr);
194	    }
195	
196	    circuit_lib.set_buffer_type(model, buf_type);
197	
198	    /* Parse the others options:
199	     * 1. size of buffer in the first stage
200	     * 2. number of levels
201	     * 3. driving strength per stage
202	     */
203	    circuit_lib.set_buffer_size(
204	      model, get_attribute(xml_design_tech, "size", loc_data).as_float(0.));
205	    circuit_lib.set_buffer_num_levels(
206	      model, get_attribute(xml_design_tech, "num_level", loc_data,
207	                           pugiutil::ReqOpt::OPTIONAL)
208	               .as_int(1));
209	    circuit_lib.set_buffer_f_per_stage(
210	      model, get_attribute(xml_design_tech, "f_per_stage", loc_data,
211	                           pugiutil::ReqOpt::OPTIONAL)
212	               .as_int(4));
213	  }
214	
215	  /* Parse exclusive attributes for pass-gate logics */
216	  if (CIRCUIT_MODEL_PASSGATE == circuit_lib.model_type(model)) {
217	    /* Identify the topology of the pass-gate logic */
218	    const char* topology_attr =
219	      get_attribute(xml_design_tech, "topology", loc_data).value();
220	    /* Translate the type of pass-gate logic to enumerate */
221	    e_circuit_model_pass_gate_logic_type passgate_type =
222	      string_to_passgate_type(std::string(topology_attr));
223	
224	    if (NUM_CIRCUIT_MODEL_PASS_GATE_TYPES == passgate_type) {
225	      archfpga_throw(loc_data.filename_c_str(), loc_data.line(xml_design_tech),
226	                     "Invalid 'topology' attribute '%s'\n", topology_attr);
227	    }
228	
229	    circuit_lib.set_pass_gate_logic_type(model, passgate_type);
230	    /* Parse the others options:
231	     * 1. pmos size to be used in the pass gate logic
232	     * 2. nmos size to be used in the pass gate logic
233	     */
234	    circuit_lib.set_pass_gate_logic_pmos_size(
235	      model,
236	      get_attribute(xml_design_tech, "pmos_size", loc_data).as_float(0.));
237	    circuit_lib.set_pass_gate_logic_nmos_size(
238	      model,
239	      get_attribute(xml_design_tech, "nmos_size", loc_data).as_float(0.));
240	  }
241	
242	  /* Parse exclusive attributes for Look-Up Tables (LUTs) */
243	  if (CIRCUIT_MODEL_LUT == circuit_lib.model_type(model)) {
244	    /* Identify if this is a fracturable LUT */
245	    circuit_lib.set_lut_is_fracturable(
246	      model, get_attribute(xml_design_tech, "fracturable_lut", loc_data,
247	                           pugiutil::ReqOpt::OPTIONAL)
248	               .as_bool(false));
249	    /* Set default MUX-relate attributes as LUT contains a tree-like MUX */
250	    circuit_lib.set_mux_structure(model, CIRCUIT_MODEL_STRUCTURE_TREE);
251	    circuit_lib.set_mux_use_local_encoder(model, false);
252	    circuit_lib.set_mux_use_advanced_rram_design(model, false);
253	  }
254	
255	  /* Parse exclusive attributes for multiplexers */
256	  if (CIRCUIT_MODEL_MUX == circuit_lib.model_type(model)) {
257	    /* Set default values for multiplexer structure */
258	    if (CIRCUIT_MODEL_DESIGN_CMOS == circuit_lib.design_tech_type(model)) {
259	      circuit_lib.set_mux_structure(model, CIRCUIT_MODEL_STRUCTURE_TREE);
260	    } else {
261	      VTR_ASSERT_SAFE(CIRCUIT_MODEL_DESIGN_RRAM ==
262	                      circuit_lib.design_tech_type(model));
263	      circuit_lib.set_mux_structure(model, CIRCUIT_MODEL_STRUCTURE_ONELEVEL);
264	    }
265	    /* Identify the topology of the multiplexer structure */
266	    const char* structure_attr =
267	      get_attribute(xml_design_tech, "structure", loc_data).value();
268	    /* Translate the type of multiplexer structure to enumerate */
269	    e_circuit_model_structure mux_structure =
270	      string_to_mux_structure_type(std::string(structure_attr));
271	
272	    if (NUM_CIRCUIT_MODEL_STRUCTURE_TYPES == mux_structure) {
273	      archfpga_throw(loc_data.filename_c_str(), loc_data.line(xml_design_tech),
274	                     "Invalid 'structure' attribute '%s'\n", structure_attr);
275	    }
276	
277	    circuit_lib.set_mux_structure(model, mux_structure);
278	
279	    /* Parse the others options:
280	     * 1. constant input values
281	     * 2. number of levels if multi-level multiplexer structure is selected
282	     * 3. if advanced ReRAM design is used
283	     * 4. if local encoder is to be used
284	     */
285	    if (true == get_attribute(xml_design_tech, "add_const_input", loc_data,
286	                              pugiutil::ReqOpt::OPTIONAL)
287	                  .as_bool(false)) {
288	      circuit_lib.set_mux_const_input_value(
289	        model,
290	        get_attribute(xml_design_tech, "const_input_val", loc_data).as_int(0));
291	    }
292	    if (CIRCUIT_MODEL_STRUCTURE_MULTILEVEL ==
293	        circuit_lib.mux_structure(model)) {
294	      circuit_lib.set_mux_num_levels(
295	        model, get_attribute(xml_design_tech, "num_level", loc_data).as_int(1));
296	      /* Correction on the mux structure:
297	       * if the number of level is set to 1 in a multi-level multiplexer,
298	       * we change the mux structure to one-level
299	       */
300	      if (1 == circuit_lib.mux_num_levels(model)) {
301	        circuit_lib.set_mux_structure(model, CIRCUIT_MODEL_STRUCTURE_ONELEVEL);
302	      }
303	    }
304	    circuit_lib.set_mux_use_advanced_rram_design(
305	      model, get_attribute(xml_design_tech, "advanced_rram_design", loc_data,
306	                           pugiutil::ReqOpt::OPTIONAL)
307	               .as_bool(false));
308	    circuit_lib.set_mux_use_local_encoder(
309	      model, get_attribute(xml_design_tech, "local_encoder", loc_data,
310	                           pugiutil::ReqOpt::OPTIONAL)
311	               .as_bool(false));
312	  }
313	
314	  /* Parse exclusive attributes for logic gates */
315	  if (CIRCUIT_MODEL_GATE == circuit_lib.model_type(model)) {
316	    /* Identify the topology of the logic gate */
317	    const char* topology_attr =
318	      get_attribute(xml_design_tech, "topology", loc_data).value();
319	    /* Translate the type of logic gate to enumerate */
320	    e_circuit_model_gate_type gate_type =
321	      string_to_gate_type(std::string(topology_attr));
322	
323	    if (NUM_CIRCUIT_MODEL_GATE_TYPES == gate_type) {
324	      archfpga_throw(loc_data.filename_c_str(), loc_data.line(xml_design_tech),
325	                     "Invalid 'topology' attribute '%s'\n", topology_attr);
326	    }
327	
328	    circuit_lib.set_gate_type(model, gate_type);
329	  }
330	
331	  /* Parse exclusive attributes for RRAM */
332	  if (CIRCUIT_MODEL_DESIGN_RRAM == circuit_lib.design_tech_type(model)) {
333	    circuit_lib.set_rram_rlrs(
334	      model, get_attribute(xml_design_tech, "ron", loc_data).as_float(0.));
335	    circuit_lib.set_rram_rhrs(
336	      model, get_attribute(xml_design_tech, "roff", loc_data).as_float(0.));
337	    circuit_lib.set_rram_wprog_set_pmos(
338	      model,
339	      get_attribute(xml_design_tech, "wprog_set_pmos", loc_data).as_float(0.));
340	    circuit_lib.set_rram_wprog_set_nmos(
341	      model,
342	      get_attribute(xml_design_tech, "wprog_set_nmos", loc_data).as_float(0.));
343	    circuit_lib.set_rram_wprog_reset_pmos(
344	      model, get_attribute(xml_design_tech, "wprog_reset_pmos", loc_data)
345	               .as_float(0.));
346	    circuit_lib.set_rram_wprog_reset_nmos(
347	      model, get_attribute(xml_design_tech, "wprog_reset_nmos", loc_data)
348	               .as_float(0.));
349	  }
350	}
