398	/********************************************************************
399	 * Identify the output mask of the port in LUTs,
400	 * by default it will be applied to each pin of this port
401	 * This is only applicable to output ports of a LUT
402	 *******************************************************************/
403	static void read_xml_output_mask(pugi::xml_node& xml_port,
404	                                 const pugiutil::loc_data& loc_data,
405	                                 CircuitLibrary& circuit_lib,
406	                                 const CircuitPortId& port) {
407	  std::string output_mask_attr =
408	    get_attribute(xml_port, "lut_output_mask", loc_data,
409	                  pugiutil::ReqOpt::OPTIONAL)
410	      .as_string();
411	  std::vector<size_t> mask_vector;
412	  if (!output_mask_attr.empty()) {
413	    /* Split the string with token ',' */
414	    openfpga::StringToken string_tokenizer(
415	      get_attribute(xml_port, "lut_output_mask", loc_data,
416	                    pugiutil::ReqOpt::OPTIONAL)
417	        .as_string(nullptr));
418	    for (const std::string& mask_token : string_tokenizer.split(',')) {
419	      mask_vector.push_back(std::atoi(mask_token.c_str()));
420	    }
421	    /* Make sure that the size of mask fits the port size */
422	    if (circuit_lib.port_size(port) != mask_vector.size()) {
423	      archfpga_throw(loc_data.filename_c_str(), loc_data.line(xml_port),
424	                     "Invalid lut_output_mask attribute '%s'! It must match "
425	                     "the port size (=%lu)\n",
426	                     output_mask_attr.c_str(), circuit_lib.port_size(port));
427	    }
428	  } else {
429	    /* By default, we give a mask vector covering each pin of the port */
430	    mask_vector.resize(circuit_lib.port_size(port));
431	    std::iota(mask_vector.begin(), mask_vector.end(), 0);
432	  }
433	  circuit_lib.set_port_lut_output_mask(port, mask_vector);
434	}
