436	/********************************************************************
437	 * This is a generic function to parse XML codes that describe
438	 * a port of a circuit model to circuit library
439	 *******************************************************************/
440	static void read_xml_circuit_port(pugi::xml_node& xml_port,
441	                                  const pugiutil::loc_data& loc_data,
442	                                  CircuitLibrary& circuit_lib,
443	                                  const CircuitModelId& model) {
444	  /* Find the type of the circuit port
445	   * so that we can add a new circuit port to circuit library
446	   */
447	  const char* type_attr = get_attribute(xml_port, "type", loc_data).value();
448	
449	  /* Translate the type of circuit model to enumerate */
450	  e_circuit_model_port_type port_type =
451	    string_to_circuit_model_port_type(std::string(type_attr));
452	
453	  if (NUM_CIRCUIT_MODEL_PORT_TYPES == port_type) {
454	    archfpga_throw(loc_data.filename_c_str(), loc_data.line(xml_port),
455	                   "Invalid 'type' attribute '%s'\n", type_attr);
456	  }
457	
458	  CircuitPortId port = circuit_lib.add_model_port(model, port_type);
459	
460	  /* Parse the name of the port */
461	  circuit_lib.set_port_prefix(
462	    port, get_attribute(xml_port, "prefix", loc_data).as_string());
463	
464	  /* Parse the name of the port in cell library. By default, the lib_name is the
465	   * same as port name */
466	  const char* lib_name_attr =
467	    get_attribute(xml_port, "lib_name", loc_data, pugiutil::ReqOpt::OPTIONAL)
468	      .as_string(nullptr);
469	  if (nullptr != lib_name_attr) {
470	    circuit_lib.set_port_lib_name(
471	      port, get_attribute(xml_port, "lib_name", loc_data).as_string());
472	  } else {
473	    circuit_lib.set_port_lib_name(port, circuit_lib.port_prefix(port));
474	  }
475	
476	  /* Parse the port size, by default it will be 1 */
477	  circuit_lib.set_port_size(
478	    port, get_attribute(xml_port, "size", loc_data).as_int(1));
479	
480	  /* Identify if the port is for io, this is only applicable to INPUT ports.
481	   * By default, it will NOT be a mode selection port
482	   */
483	  circuit_lib.set_port_is_io(
484	    port, get_attribute(xml_port, "is_io", loc_data, pugiutil::ReqOpt::OPTIONAL)
485	            .as_bool(false));
486	
487	  /* Identify if the port is a data io, ONLY applicable to I/O port
488	   * By default, it will NOT be a data io port
489	   */
490	  if (true == circuit_lib.port_is_io(port)) {
491	    circuit_lib.set_port_is_data_io(
492	      port, get_attribute(xml_port, "is_data_io", loc_data,
493	                          pugiutil::ReqOpt::OPTIONAL)
494	              .as_bool(false));
495	  }
496	
497	  /* Identify if the port is for mode selection, this is only applicable to SRAM
498	   * ports. By default, it will NOT be a mode selection port
499	   */
500	  if (CIRCUIT_MODEL_PORT_SRAM == circuit_lib.port_type(port)) {
501	    circuit_lib.set_port_is_mode_select(
502	      port, get_attribute(xml_port, "mode_select", loc_data,
503	                          pugiutil::ReqOpt::OPTIONAL)
504	              .as_bool(false));
505	  }
506	
507	  /* Identify the default value of the port, by default it will be 0 */
508	  circuit_lib.set_port_default_value(
509	    port,
510	    get_attribute(xml_port, "default_val", loc_data, pugiutil::ReqOpt::OPTIONAL)
511	      .as_int(0));
512	
513	  /* Identify the tri-state map of the port, by default it will be nullptr
514	   * This is only applicable to input ports of a LUT
515	   */
516	  if ((CIRCUIT_MODEL_LUT == circuit_lib.model_type(model)) &&
517	      (CIRCUIT_MODEL_PORT_INPUT == circuit_lib.port_type(port))) {
518	    const char* tri_state_map_attr =
519	      get_attribute(xml_port, "tri_state_map", loc_data,
520	                    pugiutil::ReqOpt::OPTIONAL)
521	        .value();
522	    if (nullptr != tri_state_map_attr) {
523	      circuit_lib.set_port_tri_state_map(
524	        port, get_attribute(xml_port, "tri_state_map", loc_data,
525	                            pugiutil::ReqOpt::OPTIONAL)
526	                .as_string());
527	    }
528	  }
529	
530	  /* Identify the fracturable-level of the port in LUTs, by default it will be
531	   * -1 This is only applicable to output ports of a LUT
532	   */
533	  if ((CIRCUIT_MODEL_LUT == circuit_lib.model_type(model)) &&
534	      (CIRCUIT_MODEL_PORT_OUTPUT == circuit_lib.port_type(port))) {
535	    circuit_lib.set_port_lut_frac_level(
536	      port, get_attribute(xml_port, "lut_frac_level", loc_data,
537	                          pugiutil::ReqOpt::OPTIONAL)
538	              .as_int(-1));
539	  }
540	
541	  /* Identify if the port carries a harden functionality rather than a
542	   * reconfigurable port This is only applicable to LUT circuit models. The
543	   * super LUT circuit model (whose netlists are supposed to be provided by
544	   * users) contains some hard logic inside, e.g., a carry logic. By default, a
545	   * port does NOT carry a hard functionality
546	   */
547	  if (CIRCUIT_MODEL_LUT == circuit_lib.model_type(model)) {
548	    circuit_lib.set_port_is_harden_lut_port(
549	      port, get_attribute(xml_port, "is_harden_lut_port", loc_data,
550	                          pugiutil::ReqOpt::OPTIONAL)
551	              .as_bool(false));
552	  }
553	
554	  /* Identify the output mask of the port in LUTs, by default it will be applied
555	   * to each pin of this port This is only applicable to output ports of a LUT
556	   */
557	  if ((CIRCUIT_MODEL_LUT == circuit_lib.model_type(model)) &&
558	      (CIRCUIT_MODEL_PORT_OUTPUT == circuit_lib.port_type(port))) {
559	    read_xml_output_mask(xml_port, loc_data, circuit_lib, port);
560	  }
561	
562	  /* Identify if the port is a global port, by default it is NOT */
563	  circuit_lib.set_port_is_global(
564	    port,
565	    get_attribute(xml_port, "is_global", loc_data, pugiutil::ReqOpt::OPTIONAL)
566	      .as_bool(false));
567	
568	  /* Identify if the port is a reset port, by default it is NOT */
569	  circuit_lib.set_port_is_reset(
570	    port,
571	    get_attribute(xml_port, "is_reset", loc_data, pugiutil::ReqOpt::OPTIONAL)
572	      .as_bool(false));
573	
574	  /* Identify if the port is a set port, by default it is NOT */
575	  circuit_lib.set_port_is_set(port, get_attribute(xml_port, "is_set", loc_data,
576	                                                  pugiutil::ReqOpt::OPTIONAL)
577	                                      .as_bool(false));
578	
579	  /* Identify if the port is in programming purpose, by default it is NOT */
580	  circuit_lib.set_port_is_prog(
581	    port,
582	    get_attribute(xml_port, "is_prog", loc_data, pugiutil::ReqOpt::OPTIONAL)
583	      .as_bool(false));
584	
585	  /* Identify if the port is in shift register purpose, by default it is NOT */
586	  circuit_lib.set_port_is_shift_register(
587	    port, get_attribute(xml_port, "is_shift_register", loc_data,
588	                        pugiutil::ReqOpt::OPTIONAL)
589	            .as_bool(false));
590	
591	  /* Identify if the port is to enable programming for FPGAs, by default it is
592	   * NOT */
593	  circuit_lib.set_port_is_config_enable(
594	    port, get_attribute(xml_port, "is_config_enable", loc_data,
595	                        pugiutil::ReqOpt::OPTIONAL)
596	            .as_bool(false));
597	
598	  /* Find the name of circuit model that this port is linked to */
599	  circuit_lib.set_port_tri_state_model_name(
600	    port, get_attribute(xml_port, "circuit_model_name", loc_data,
601	                        pugiutil::ReqOpt::OPTIONAL)
602	            .as_string());
603	
604	  /* Find the name of circuit model that port is used for inversion of signals,
605	   * This is only applicable to BL/WL/BLB/WLB ports
606	   */
607	  if ((CIRCUIT_MODEL_PORT_BL == circuit_lib.port_type(port)) ||
608	      (CIRCUIT_MODEL_PORT_WL == circuit_lib.port_type(port)) ||
609	      (CIRCUIT_MODEL_PORT_BLB == circuit_lib.port_type(port)) ||
610	      (CIRCUIT_MODEL_PORT_WLB == circuit_lib.port_type(port))) {
611	    circuit_lib.set_port_inv_model_name(
612	      port, get_attribute(xml_port, "inv_circuit_model_name", loc_data,
613	                          pugiutil::ReqOpt::OPTIONAL)
614	              .as_string());
615	  }
616	}
617	
618	/********************************************************************
619	 * This is a generic function to parse XML codes that describe
620	 * RC parasitics for wire circuit model to circuit library
621	 *******************************************************************/
622	static void read_xml_wire_param(pugi::xml_node& xml_wire_param,
623	                                const pugiutil::loc_data& loc_data,
624	                                CircuitLibrary& circuit_lib,
625	                                const CircuitModelId& model) {
626	  /* Find the type of the wire model */
627	  const char* type_attr =
628	    get_attribute(xml_wire_param, "model_type", loc_data).value();
629	
630	  /* Translate the type of circuit model to enumerate */
631	  e_wire_model_type wire_model_type =
632	    string_to_wire_model_type(std::string(type_attr));
633	
634	  if (NUM_WIRE_MODEL_TYPES == wire_model_type) {
635	    archfpga_throw(loc_data.filename_c_str(), loc_data.line(xml_wire_param),
636	                   "Invalid 'type' attribute '%s'\n", type_attr);
637	  }
638	
639	  circuit_lib.set_wire_type(model, wire_model_type);
640	
641	  /* Parse the R and C values */
642	  circuit_lib.set_wire_r(
643	    model, get_attribute(xml_wire_param, "R", loc_data).as_float(0.));
644	  circuit_lib.set_wire_c(
645	    model, get_attribute(xml_wire_param, "C", loc_data).as_float(0.));
646	
647	  /* Parse the number of levels for the wire model */
648	  circuit_lib.set_wire_num_level(
649	    model, get_attribute(xml_wire_param, "num_level", loc_data).as_int(0));
650	}
651	
652	/********************************************************************
653	 * This is a generic function to parse XML codes that describe
654	 * a delay matrix for a circuit model to circuit library
655	 *******************************************************************/
656	static void read_xml_delay_matrix(pugi::xml_node& xml_delay_matrix,
657	                                  const pugiutil::loc_data& loc_data,
658	                                  CircuitLibrary& circuit_lib,
659	                                  const CircuitModelId& model) {
660	  /* Find the type of the delay model, so that we can add to circuit library */
661	  const char* type_attr =
662	    get_attribute(xml_delay_matrix, "type", loc_data).value();
663	
664	  /* Translate the type of delay matrix for a circuit model to enumerate */
665	  e_circuit_model_delay_type delay_type =
666	    string_to_circuit_model_delay_type(std::string(type_attr));
667	
668	  if (NUM_CIRCUIT_MODEL_DELAY_TYPES == delay_type) {
669	    archfpga_throw(loc_data.filename_c_str(), loc_data.line(xml_delay_matrix),
670	                   "Invalid 'type' attribute '%s'\n", type_attr);
671	  }
672	
673	  circuit_lib.add_delay_info(model, delay_type);
674	
675	  /* Parse the input ports */
676	  circuit_lib.set_delay_in_port_names(
677	    model, delay_type,
678	    get_attribute(xml_delay_matrix, "in_port", loc_data).as_string());
679	
680	  /* Parse the output ports */
681	  circuit_lib.set_delay_out_port_names(
682	    model, delay_type,
683	    get_attribute(xml_delay_matrix, "out_port", loc_data).as_string());
684	
685	  /* Parse the delay values */
686	  circuit_lib.set_delay_values(model, delay_type,
687	                               std::string(xml_delay_matrix.child_value()));
688	}
689	
690	/********************************************************************
691	 * Parse XML codes of a circuit model to circuit library
692	 *******************************************************************/
693	static void read_xml_circuit_model(pugi::xml_node& xml_model,
694	                                   const pugiutil::loc_data& loc_data,
695	                                   CircuitLibrary& circuit_lib) {
696	  /* Find the type of the circuit model
697	   * so that we can add a new circuit model to circuit library
698	   */
699	  const char* type_attr = get_attribute(xml_model, "type", loc_data).value();
700	
701	  /* Translate the type of circuit model to enumerate */
702	  e_circuit_model_type model_type =
703	    string_to_circuit_model_type(std::string(type_attr));
704	
705	  if (NUM_CIRCUIT_MODEL_TYPES == model_type) {
706	    archfpga_throw(loc_data.filename_c_str(), loc_data.line(xml_model),
707	                   "Invalid 'type' attribute '%s'\n", type_attr);
708	  }
709	
710	  CircuitModelId model = circuit_lib.add_model(model_type);
711	
712	  /* Find the name of the circuit model */
713	  const char* name_attr = get_attribute(xml_model, "name", loc_data).value();
714	  circuit_lib.set_model_name(model, std::string(name_attr));
715	
716	  /* TODO: This attribute is going to be DEPRECATED
717	   * Find the prefix of the circuit model
718	   */
719	  const char* prefix_attr =
720	    get_attribute(xml_model, "prefix", loc_data).value();
721	  circuit_lib.set_model_prefix(model, std::string(prefix_attr));
722	
723	  /* Find a SPICE netlist which is an optional attribute*/
724	  circuit_lib.set_model_spice_netlist(
725	    model, get_attribute(xml_model, "spice_netlist", loc_data,
726	                         pugiutil::ReqOpt::OPTIONAL)
727	             .as_string(""));
728	
729	  /* Find a Verilog netlist which is an optional attribute*/
730	  circuit_lib.set_model_verilog_netlist(
731	    model, get_attribute(xml_model, "verilog_netlist", loc_data,
732	                         pugiutil::ReqOpt::OPTIONAL)
733	             .as_string(""));
734	
735	  /* Find if the circuit model is default in its type */
736	  circuit_lib.set_model_is_default(
737	    model,
738	    get_attribute(xml_model, "is_default", loc_data, pugiutil::ReqOpt::OPTIONAL)
739	      .as_bool(false));
740	
741	  /* Find if the circuit model is should be dumped in structural verilog */
742	  circuit_lib.set_model_dump_structural_verilog(
743	    model, get_attribute(xml_model, "dump_structural_verilog", loc_data,
744	                         pugiutil::ReqOpt::OPTIONAL)
745	             .as_bool(false));
746	
747	  /* Parse attributes under the <circuit_model> */
748	  /* Design technology -related attributes */
749	  read_xml_model_design_technology(xml_model, loc_data, circuit_lib, model);
750	
751	  /* Parse special buffer attributes required by LUTs only */
752	  if (CIRCUIT_MODEL_LUT == circuit_lib.model_type(model)) {
753	    /* Input buffer of LUTs */
754	    auto xml_input_buffer =
755	      get_single_child(xml_model, "lut_input_buffer", loc_data);
756	    std::string input_buffer_circuit_model_name =
757	      read_xml_buffer(xml_input_buffer, loc_data);
758	    circuit_lib.set_model_lut_input_buffer(
759	      model, true != input_buffer_circuit_model_name.empty(),
760	      input_buffer_circuit_model_name);
761	
762	    /* Input inverter of LUTs */
763	    auto xml_input_inverter =
764	      get_single_child(xml_model, "lut_input_inverter", loc_data);
765	    std::string input_inverter_circuit_model_name =
766	      read_xml_buffer(xml_input_inverter, loc_data);
767	    circuit_lib.set_model_lut_input_inverter(
768	      model, true != input_inverter_circuit_model_name.empty(),
769	      input_inverter_circuit_model_name);
770	
771	    /* Intermediate buffer of LUTs */
772	    auto xml_intermediate_buffer =
773	      get_single_child(xml_model, "lut_intermediate_buffer", loc_data,
774	                       pugiutil::ReqOpt::OPTIONAL);
775	    if (xml_intermediate_buffer) {
776	      std::string intermediate_buffer_circuit_model_name =
777	        read_xml_buffer(xml_intermediate_buffer, loc_data);
778	      circuit_lib.set_model_lut_intermediate_buffer(
779	        model, true != intermediate_buffer_circuit_model_name.empty(),
780	        intermediate_buffer_circuit_model_name);
781	      /* If intermediate buffer is defined, try to find the location map */
782	      if (true != intermediate_buffer_circuit_model_name.empty()) {
783	        circuit_lib.set_model_lut_intermediate_buffer_location_map(
784	          model,
785	          get_attribute(xml_intermediate_buffer, "location_map", loc_data)
786	            .as_string());
787	      }
788	    }
789	  }
790	
791	  /* Parse device technology attributes
792	   * This is applicable to only atom circuit models:
793	   * - inverter/buffer
794	   * - pass gate
795	   * - logic gates
796	   */
797	  if ((CIRCUIT_MODEL_INVBUF == circuit_lib.model_type(model)) ||
798	      (CIRCUIT_MODEL_PASSGATE == circuit_lib.model_type(model)) ||
799	      (CIRCUIT_MODEL_GATE == circuit_lib.model_type(model))) {
800	    read_xml_model_device_technology(xml_model, loc_data, circuit_lib, model);
801	  }
802	
803	  /* Input buffer attributes, NOT required for circuit models which are
804	   * inverters or buffers */
805	  if (CIRCUIT_MODEL_INVBUF != circuit_lib.model_type(model)) {
806	    auto xml_input_buffer =
807	      get_single_child(xml_model, "input_buffer", loc_data);
808	    std::string input_buffer_circuit_model_name =
809	      read_xml_buffer(xml_input_buffer, loc_data);
810	    circuit_lib.set_model_input_buffer(
811	      model, true != input_buffer_circuit_model_name.empty(),
812	      input_buffer_circuit_model_name);
813	  }
814	
815	  /* Output buffer attributes, NOT required for circuit models which are
816	   * inverters or buffers */
817	  if (CIRCUIT_MODEL_INVBUF != circuit_lib.model_type(model)) {
818	    auto xml_output_buffer =
819	      get_single_child(xml_model, "output_buffer", loc_data);
820	    std::string output_buffer_circuit_model_name =
821	      read_xml_buffer(xml_output_buffer, loc_data);
822	    circuit_lib.set_model_output_buffer(
823	      model, true != output_buffer_circuit_model_name.empty(),
824	      output_buffer_circuit_model_name);
825	  }
826	
827	  /* Pass-gate-logic attributes, required by LUT and MUX */
828	  if ((CIRCUIT_MODEL_LUT == circuit_lib.model_type(model)) ||
829	      (CIRCUIT_MODEL_MUX == circuit_lib.model_type(model))) {
830	    auto xml_pass_gate_logic =
831	      get_single_child(xml_model, "pass_gate_logic", loc_data);
832	    circuit_lib.set_model_pass_gate_logic(
833	      model, get_attribute(xml_pass_gate_logic, "circuit_model_name", loc_data)
834	               .as_string());
835	    /* Last stage pass gate is optional */
836	    size_t num_last_stage_pgl =
837	      count_children(xml_model, "last_stage_pass_gate_logic", loc_data,
838	                     pugiutil::ReqOpt::OPTIONAL);
839	    if (0 < num_last_stage_pgl) {
840	      auto xml_last_stage_pass_gate_logic =
841	        get_single_child(xml_model, "last_stage_pass_gate_logic", loc_data);
842	      circuit_lib.set_model_last_stage_pass_gate_logic(
843	        model, get_attribute(xml_last_stage_pass_gate_logic,
844	                             "circuit_model_name", loc_data)
845	                 .as_string());
846	    } else {
847	      /* By default, assume the last stage circuit model is the same as others
848	       */
849	      circuit_lib.set_model_last_stage_pass_gate_logic(
850	        model,
851	        get_attribute(xml_pass_gate_logic, "circuit_model_name", loc_data)
852	          .as_string());
853	    }
854	  }
855	
856	  /* Parse all the ports belonging to this circuit model
857	   * We count the number of ports in total and then add one by one
858	   */
859	  size_t num_ports =
860	    count_children(xml_model, "port", loc_data, pugiutil::ReqOpt::OPTIONAL);
861	  if (0 < num_ports) {
862	    pugi::xml_node xml_port = get_first_child(xml_model, "port", loc_data);
863	    while (xml_port) {
864	      read_xml_circuit_port(xml_port, loc_data, circuit_lib, model);
865	      xml_port = xml_port.next_sibling(xml_port.name());
866	    }
867	  }
868	
869	  /* Parse the parasitics of wires */
870	  if ((CIRCUIT_MODEL_WIRE == circuit_lib.model_type(model)) ||
871	      (CIRCUIT_MODEL_CHAN_WIRE == circuit_lib.model_type(model))) {
872	    auto xml_wire_param = get_single_child(xml_model, "wire_param", loc_data);
873	    read_xml_wire_param(xml_wire_param, loc_data, circuit_lib, model);
874	  }
875	
876	  /* Parse all the delay matrix if defined */
877	  size_t num_delay_matrix = count_children(xml_model, "delay_matrix", loc_data,
878	                                           pugiutil::ReqOpt::OPTIONAL);
879	  if (0 < num_delay_matrix) {
880	    pugi::xml_node xml_delay_matrix =
881	      get_first_child(xml_model, "delay_matrix", loc_data);
882	    while (xml_delay_matrix) {
883	      read_xml_delay_matrix(xml_delay_matrix, loc_data, circuit_lib, model);
884	      xml_delay_matrix = xml_delay_matrix.next_sibling(xml_delay_matrix.name());
885	    }
886	  }
887	}
888	
889	/********************************************************************
890	 * Parse XML codes about circuit models to circuit library
891	 *******************************************************************/
892	CircuitLibrary read_xml_circuit_library(pugi::xml_node& Node,
893	                                        const pugiutil::loc_data& loc_data) {
894	  CircuitLibrary circuit_lib;
895	
896	  /* Iterate over the children under this node,
897	   * each child should be named after circuit_model
898	   */
899	  for (pugi::xml_node xml_model : Node.children()) {
900	    /* Error out if the XML child has an invalid name! */
901	    if (xml_model.name() != std::string("circuit_model")) {
902	      bad_tag(xml_model, loc_data, Node, {"circuit_model"});
903	    }
904	    read_xml_circuit_model(xml_model, loc_data, circuit_lib);
905	  }
906	
907	  return circuit_lib;
908	}
