1	/************************************************************************
2	 * Check functions for the content of config protocol to avoid conflicts with
3	 * other data structures
4	 * These functions are not universal methods for the ConfigProtocol class
5	 * They are made to ease the development in some specific purposes
6	 * Please classify such functions in this file
7	 ***********************************************************************/
8	#include "check_config_protocol.h"
9	
10	#include "circuit_library_utils.h"
11	#include "vtr_assert.h"
12	#include "vtr_log.h"
13	
14	/* begin namespace openfpga */
15	namespace openfpga {
16	
17	/********************************************************************
18	 * Check if the programming clock port defined in configuration protocol is a
19	 *valid global programming clock of a ccff model
20	 *******************************************************************/
21	static int check_config_protocol_programming_clock(
22	  const ConfigProtocol& config_protocol, const CircuitLibrary& circuit_lib) {
23	  int num_err = 0;
24	  /* Programming clock is only available for CCFF */
25	  if (config_protocol.type() != CONFIG_MEM_SCAN_CHAIN) {
26	    return num_err;
27	  }
28	  /* Must find a CCFF model */
29	  std::vector<CircuitModelId> ccff_models =
30	    circuit_lib.models_by_type(CIRCUIT_MODEL_CCFF);
31	  if (ccff_models.empty()) {
32	    VTR_LOG_ERROR(
33	      "Expect at least one CCFF model to be defined in circuit library!\n");
34	    num_err++;
35	  }
36	  /* Try to match the programming clock port name with the CCFF port name */
37	  for (BasicPort prog_clk_port : config_protocol.prog_clock_pins()) {
38	    bool port_match = false;
39	    for (CircuitModelId ccff_model : ccff_models) {
40	      CircuitPortId circuit_port =
41	        circuit_lib.model_port(ccff_model, prog_clk_port.get_name());
42	      if (circuit_port) {
43	        port_match = true;
44	        /* Ensure this is a programming clock and a global port */
45	        if (!circuit_lib.port_is_global(circuit_port)) {
46	          VTR_LOG_ERROR(
47	            "Expect the programming clock '%s' to be a global port but not!\n",
48	            prog_clk_port.get_name().c_str());
49	          num_err++;
50	        }
51	        if (circuit_lib.port_type(circuit_port) != CIRCUIT_MODEL_PORT_CLOCK) {
52	          VTR_LOG_ERROR(
53	            "Expect the programming clock '%s' to be a clock port but not!\n",
54	            prog_clk_port.get_name().c_str());
55	          num_err++;
56	        }
57	        if (!circuit_lib.port_is_prog(circuit_port)) {
58	          VTR_LOG_ERROR(
59	            "Expect the programming clock '%s' to be a programming port but "
60	            "not!\n",
